  ('aboriginal-57f41407-moex-00523', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '公示催告程序，持有證券人於申報權利期間，申報權利並提出證券，聲請人閱覽證券，認其為真正而無爭 執時，下列敘述何者正確？', '["法院應裁定駁回公示催告之聲請", "法院應依聲請裁定終結公示催告程序，由法院書記官通知聲請人及申報權利人", "法院應依職權裁定終結公示催告程序，毋庸通知聲請人及申報權利人", "公示催告程序終結，由法院書記官通知聲請人及申報權利人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
