  ('aboriginal-57f41407-moex-00526', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲、乙兩人共同毆打A成傷。二日後，甲又另外竊取B的財物。下列敘述何者正確？', '["檢察官對於甲傷害罪的起訴，其效力及於乙的傷害罪", "檢察官起訴甲的傷害罪後，法院得一併審判其竊盜罪案件", "檢察官對於甲傷害罪的起訴，其效力不及於甲的竊盜罪", "檢察官起訴甲的傷害罪後，法院得一併審判乙的傷害罪案件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "9acea49fa720", "answer_pdf_sha1": "85b04c6abf8a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
